          sANNOTATION_PLANE_ELEMENT>.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]ELEMENTS for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( ELEMENTS: p0 )
      }
    }
  }
}
